func toURLAndHeaders(urlParts []any) (string, map[string]any) {
	if len(urlParts) == 0 {
		return "", nil
	}

	headers, err := maps.ToStringMapE(urlParts[len(urlParts)-1])
	if err == nil {
		urlParts = urlParts[:len(urlParts)-1]
	} else {
		headers = nil
	}

	return strings.Join(cast.ToStringSlice(urlParts), ""), headers
}
